class SearchNode:
    def __init__(self, action, state, parent):
        self.state = state
        self.action = action
        self.parent = parent
    def path(self):
        if self.parent == None:
            return [(self.action, self.state)]
        else:
            return self.parent.path() + [(self.action, self.state)]
    def inPath(self, s):
        if s == self.state:
            return True
        elif self.parent == None:
            return False
        else:
            return self.parent.inPath(s)

def breadthFirstSearch(initialState, goalTest, actions, successor):
    agenda = Queue()
    if goalTest(initialState):
        return [(None, initialState)]
    agenda.push(SearchNode(None, initialState, None))
    while not agenda.isEmpty():
        parent = agenda.pop()
        newChildStates = []
        for a in actions(parent.state):
            newS = successor(parent.state, a)
            newN = SearchNode(a, newS, parent)
            if goalTest(newS):
                return newN.path()
            elif newS in newChildStates:
                pass
            elif parent.inPath(newS):
                pass
            else:
                newChildStates.append(newS)
                agenda.push(newN)
    return None

use std::collections::VecDeque;

pub fn bfs(arr: &[i32]) -> Vec<i32> {
    if arr.len() < 2 {
        return Vec::new();
    }

    let n = arr[0] as usize;
    let m = arr[1] as usize;

    if arr.len() < 2 + 2 * m + 1 {
        return Vec::new();
    }

    let start = arr[2 + 2 * m] as usize;
    if start >= n {
        return Vec::new();
    }

    let mut adj = vec![vec![]; n];
    for i in 0..m {
        let u = arr[2 + 2 * i] as usize;
        let v = arr[2 + 2 * i + 1] as usize;
        if u < n && v < n {
            adj[u].push(v);
            adj[v].push(u);
        }
    }

    for i in 0..n {
        adj[i].sort();
    }

    let mut result = Vec::new();
    let mut visited = vec![false; n];
    let mut q = VecDeque::new();

    visited[start] = true;
    q.push_back(start);

    while let Some(u) = q.pop_front() {
        result.push(u as i32);

        for &v in &adj[u] {
            let v_usize = v;
            if !visited[v_usize] {
                visited[v_usize] = true;
                q.push_back(v_usize);
            }
        }
    }

    result
}

